request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?endLikeType ?endName ?endId WHERE {
  VALUES ?choreo {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-89c72dc1-47d9-4218-bcfb-be69509c6221>
  }

  ?start bbo:name ?startName .
  ?start tai:belongsTo ?choreo .
  ?start a bboExt:StartEvent .

  ?reachable ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
  FILTER(?reachable = ?start)
  ?end tai:belongsTo ?choreo .

  {
    ?end a bboExt:EndEvent .
    BIND("EndEvent" AS ?endLikeType)
  }
  UNION
  {
    ?end a bboExt:TerminateEventDefinition .
    BIND("TerminateEventDefinition" AS ?endLikeType)
  }
  OPTIONAL { ?end bbo:name ?endName . }
  OPTIONAL { ?end bbo:id ?endId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?type ?name ?id WHERE {
  VALUES ?choreo {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-89c72dc1-47d9-4218-bcfb-be69509c6221>
  }

  ?endLike tai:belongsTo ?choreo .
  ?endLike a ?type .

  FILTER(
    (?type = bboExt:EndEvent) ||
    (CONTAINS(LCASE(STR(?type)), "endevent")) ||
    (CONTAINS(LCASE(STR(?type)), "terminate")) ||
    (CONTAINS(LCASE(STR(?type)), "end"))
  )

  OPTIONAL { ?endLike bbo:name ?name . }
  OPTIONAL { ?endLike bbo:id ?id . }
}
LIMIT 25
